import { nodeApi, dotnetApi } from '../axios';
import { ENDPOINTS } from '../config';
import { postFormData } from '../helpers';

/**
 * Group service — matches mobile app's exact service patterns.
 * See actions/group_actions.js
 */
const groupService = {
  // createGroupAttempt → post_service5 (BASE_URL_3, JSON + token)
  createGroup: (data) => dotnetApi.post(ENDPOINTS.SUBMIT_PRIVATE_GROUP, data),
  // (same as create for private)
  createPrivateGroup: (data) => dotnetApi.post(ENDPOINTS.SUBMIT_PRIVATE_GROUP, data),
  // getGroupsListAttempt → post_services2 (BASE_URL_3, JSON)
  getGroupList: (data) => dotnetApi.post(ENDPOINTS.GET_GROUP_LIST, data || {}),
  // getAllGroupsListForJoinAttempt → post_services2 (BASE_URL_3, JSON)
  getDiscoverGroups: (params) => dotnetApi.post(ENDPOINTS.GET_GROUPS, params || {}),
  // requestSendForJoinGroupAttempt → post_services2 (BASE_URL_3, JSON)
  submitJoinRequest: (data) => dotnetApi.post(ENDPOINTS.SUBMIT_GROUP_REQUEST, data),
  // groupRequestsAttempt → post_services2 (BASE_URL_3, JSON)
  getJoinRequests: (params) => dotnetApi.post(ENDPOINTS.GET_GROUP_REQUEST, params || {}),
  // groupRequestAcceptAttempt → post_services2 (BASE_URL_3, JSON)
  processJoinRequest: (data) => dotnetApi.post(ENDPOINTS.PROCESS_GROUP_REQUEST, data),
  // DeleteGroupAttempt → post_services (BASE_URL, FormData + token)
  deleteGroup: (params) => postFormData(nodeApi, ENDPOINTS.DELETE_GROUP, params),
  // getGroupMembersAttempt → post_services (BASE_URL, FormData + token)
  getGroupMembers: (params) => postFormData(nodeApi, ENDPOINTS.GET_GROUP_MEMBERS, params),
  // addGroupMembersAttempt → post_services (BASE_URL, FormData + token)
  addMember: (params) => postFormData(nodeApi, ENDPOINTS.ADD_MEMBER, params),
  // deleteGroupMembersAttempt → post_services (BASE_URL, FormData + token)
  deleteMember: (params) => postFormData(nodeApi, ENDPOINTS.DELETE_MEMBER, params),
  // GroupLeftAttempt → post_services (BASE_URL, FormData + token)
  leftGroup: (params) => postFormData(nodeApi, ENDPOINTS.LEFT_GROUP, params),
  // createGroupPostAttempt → post_services (BASE_URL, FormData multipart + token)
  createGroupPost: (formData) => nodeApi.post(ENDPOINTS.CREATE_GROUP_POST, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  // getGroupPostAttempt → post_services (BASE_URL, FormData + token)
  getGroupPosts: (params) => postFormData(nodeApi, ENDPOINTS.GET_GROUP_POSTS, params),
  // GET_GROUP_DETAILS → post_services (BASE_URL, FormData + token)
  getGroupDetails: (params) => postFormData(nodeApi, ENDPOINTS.GET_GROUP_DETAILS, params),
  // UPDATE_GROUP_ENDPOINT → post_service5 (BASE_URL_3, JSON + token)
  updateGroup: (data) => dotnetApi.post(ENDPOINTS.UPDATE_GROUP, data),
  // ADD_ADMIN_TO_GROUP_END_POINT → post_service5 (BASE_URL_3, JSON + token)
  addGroupAdmin: (data) => dotnetApi.post(ENDPOINTS.ADD_GROUP_ADMIN, data),
  // GROUP_STATUS_CHANGE → raw fetch (BASE_URL_5, JSON + token)
  pauseGroup: (data) => dotnetApi.post(ENDPOINTS.PAUSE_GROUP, data),
  // UPLOAD_GROUP_PROFILE_PIC → post_services (BASE_URL, FormData multipart + token)
  updateGroupIcon: (formData) => nodeApi.post(ENDPOINTS.UPDATE_GROUP_ICON, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
};

export default groupService;
