import { createAsyncThunk } from '@reduxjs/toolkit';
import { nodeApi } from '../../api/axios';
import { ENDPOINTS } from '../../api/config';
import { postFormData, getNode, putNoBody } from '../../api/helpers';
import { connectSocket, disconnectSocket } from '../../api/socket';

export const loginUser = createAsyncThunk(
  'auth/login',
  async ({ email, password }, { rejectWithValue }) => {
    try {
      const formData = new FormData();
      formData.append('email', email);
      formData.append('password', password);
      formData.append('deviceType', 'ANDROID');
      formData.append('deviceToken', 'web_client');
      formData.append('latitude', '0');
      formData.append('longitude', '0');
      const response = await nodeApi.post(ENDPOINTS.LOGIN, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      const userData = response.data?.data?.customerData || response.data?.data || response.data;
      const token = userData?.accessToken || response.data?.data?.accessToken;
      connectSocket(userData?._id || userData?.id);
      return {
        user: userData,
        token: token,
      };
    } catch (error) {
      return rejectWithValue(
        error.response?.data?.message || 'Login failed. Please try again.'
      );
    }
  }
);

export const registerUser = createAsyncThunk(
  'auth/register',
  async (userData, { rejectWithValue }) => {
    try {
      const formData = new FormData();
      Object.keys(userData).forEach((key) => formData.append(key, userData[key]));
      formData.append('deviceType', 'ANDROID');
      formData.append('deviceToken', 'web_client');
      formData.append('latitude', '0');
      formData.append('longitude', '0');
      const response = await nodeApi.post(ENDPOINTS.REGISTER, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      const resData = response.data?.data?.customerData || response.data?.data || response.data;
      const token = resData?.accessToken || response.data?.data?.accessToken;
      connectSocket(resData?._id || resData?.id);
      return {
        user: resData,
        token: token,
      };
    } catch (error) {
      return rejectWithValue(
        error.response?.data?.message || 'Registration failed. Please try again.'
      );
    }
  }
);

