import { nodeApi, dotnetApi, dotnetCustomerApi } from '../axios';
import { ENDPOINTS } from '../config';
import { postFormData, getNode } from '../helpers';

/**
 * Chat service — matches mobile app's exact service patterns.
 * See actions/auth_actions.js for chat-related calls
 */
const chatService = {
  // SendTextMessageAttempt → post_services (BASE_URL, FormData + token)
  sendMessage: (params) => postFormData(nodeApi, ENDPOINTS.SEND_MESSAGE, params),
  // GetTextMessageAttempt → get_services (BASE_URL, GET + token)
  getMessages: (params) => getNode(nodeApi, ENDPOINTS.GET_MESSAGES, params),
  // ChatMediaMessageAttempt → post_services (BASE_URL, FormData multipart + token)
  sendMedia: (formData) => nodeApi.post(ENDPOINTS.SEND_MEDIA, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  // DELETE_CHAT_MESSAGE_ENDPOINT → post_service5 (BASE_URL_3, JSON + token)
  deleteChat: (data) => dotnetApi.post(ENDPOINTS.DELETE_CHAT, data),
  // GET_CHAT_NOTIFICATION_END_POINT → post_services2 (BASE_URL_3, JSON)
  getChatList: () => dotnetApi.post(ENDPOINTS.GET_CHAT_LIST, {}),
  // READ_CHAT_NOTIFICATION_END_POINT → post_services2 (BASE_URL_3, JSON)
  readChat: (data) => dotnetApi.post(ENDPOINTS.READ_CHAT, data),
  // DELETE_CHAT_NOTIFICATION_END_POINT → post_services2 (BASE_URL_3, JSON)
  deleteAllChat: (data) => dotnetApi.post(ENDPOINTS.DELETE_ALL_CHAT, data),
  // READ_TAB_COUNTER_NOTIFICATION_END_POINT → post_services2 (BASE_URL_3, JSON)
  getUnreadCount: () => dotnetApi.post(ENDPOINTS.GET_UNREAD_COUNT, {}),
  // IS_CHAT_SUBSCRIBED → Customer endpoint
  isChatSubscribed: (data) => dotnetCustomerApi.post(ENDPOINTS.IS_CHAT_SUBSCRIBED, data),
  processChatPayment: (data) => dotnetCustomerApi.post(ENDPOINTS.PROCESS_CHAT_PAYMENT, data),
};

export default chatService;
