import { nodeApi, dotnetApi, dotnetCustomerApi } from '../axios';
import { ENDPOINTS } from '../config';
import { postFormData } from '../helpers';

/**
 * Friend service — matches mobile app's exact service patterns.
 * See actions/friends_action.js
 */
const friendService = {
  // getFriendsListAttempt → raw fetch (BASE_URL, POST, JSON body + token)
  // NOTE: Mobile uses raw fetch with JSON for this one, not FormData
  getFriendList: (params) => nodeApi.post(ENDPOINTS.GET_FRIEND_LIST, params, {
    headers: { 'Content-Type': 'application/json' },
  }),
  // GET_FRIEND_COUNT_ENDPOINT → post_services2 (BASE_URL_3, JSON)
  getFriendCount: (params) => dotnetApi.post(ENDPOINTS.GET_FRIEND_COUNT, params),
  // searchUserAttempt → post_services (BASE_URL, FormData + token)
  searchUser: (params) => postFormData(nodeApi, ENDPOINTS.SEARCH_USER, params),
  // friendRequestSendAttempt → post_services (BASE_URL, FormData + token)
  sendFriendRequest: (params) => postFormData(nodeApi, ENDPOINTS.SEND_FRIEND_REQUEST, params),
  // friendRequestAcceptAttempt → post_services (BASE_URL, FormData + token)
  acceptFriendRequest: (params) => postFormData(nodeApi, ENDPOINTS.ACCEPT_FRIEND_REQUEST, params),
  // unfriendAttempt → post_services2 (BASE_URL_3, JSON)
  deleteFriend: (data) => dotnetApi.post(ENDPOINTS.DELETE_FRIEND, data),
  // getSuggestionAttempt → post_services2 (BASE_URL_3, JSON)
  getSuggestions: (params) => dotnetApi.post(ENDPOINTS.GET_SUGGESTION, params || {}),
  // GET_NEAR_BY → Customer endpoint GET
  getNearby: (params) => dotnetCustomerApi.get(ENDPOINTS.GET_NEARBY, { params }),
  // FIND_FRIRND_OR_NOT_END_POINT → Customer endpoint GET
  isFriend: (params) => dotnetCustomerApi.get(ENDPOINTS.IS_FRIEND, { params }),
  // getUserProfileAttempt → post_services (BASE_URL, FormData + token)
  getOtherProfile: (params) => postFormData(nodeApi, ENDPOINTS.GET_OTHER_PROFILE, params),
};

export default friendService;
