import { io } from 'socket.io-client';

// Call signaling uses port 3000 (matching mobile app's mysocket.js)
const CALL_SOCKET_URL = 'http://107.180.75.184:3000';
let callSocket = null;

export const connectCallSocket = () => {
  if (callSocket && callSocket.connected) return callSocket;

  callSocket = io(CALL_SOCKET_URL, {
    transports: ['websocket'],
    reconnection: true,
    reconnectionDelay: 1000,
  });

  callSocket.on('connect', () => {
    console.log('Call socket connected:', callSocket.id);
  });

  callSocket.on('disconnect', (reason) => {
    console.log('Call socket disconnected:', reason);
  });

  return callSocket;
};

export const getCallSocket = () => callSocket;

export const sendToPeer = (messageType, payload, callType, callerName1, callerName2, callerID1, callerID2) => {
  if (!callSocket) return;
  callSocket.emit(messageType, {
    socketID: callSocket.id,
    payload,
    callType,
    callerName1,
    callerName2,
    callerID1,
    callerID2,
  });
};

export const onOffer = (callback) => {
  if (!callSocket) return;
  callSocket.on('onOffer', (sdp, callType, callerName1, callerName2, callerID1, callerID2) => {
    callback(sdp, callType, callerName1, callerName2, callerID1, callerID2);
  });
};

export const onAnswer = (callback) => {
  if (!callSocket) return;
  callSocket.on('onAnswer', (sdp, callType, callerName1, callerName2, callerID1, callerID2) => {
    callback(sdp, callType, callerName1, callerName2, callerID1, callerID2);
  });
};

export const onCandidate = (callback) => {
  if (!callSocket) return;
  callSocket.on('candidate', (candidate) => {
    callback(candidate);
  });
};

export const onCancelCall = (callback) => {
  if (!callSocket) return;
  callSocket.on('cancelCall', (res) => {
    callback(res);
  });
};

export const emitCallStatus = (callerId, receiverId, status, channelName) => {
  if (!callSocket) return;
  callSocket.emit('callStatus', {
    callerId,
    receiverId,
    status, // 1=calling, 2=accepted, 3=decline, 4=missed, 5=completed
    channel_name: channelName,
  });
};

export const disconnectCallSocket = () => {
  if (callSocket) {
    callSocket.removeAllListeners();
    callSocket.disconnect();
    callSocket = null;
  }
};
