import { createAsyncThunk } from '@reduxjs/toolkit';
import { nodeApi, dotnetApi } from '../../api/axios';
import { ENDPOINTS } from '../../api/config';
import { getNode, postFormData } from '../../api/helpers';

// GetNotificationAttempt → get_services (BASE_URL, GET + token)
export const fetchNotifications = createAsyncThunk(
  'notifications/fetch',
  async ({ skip = 0, limit = 30 }, { rejectWithValue }) => {
    try {
      const response = await getNode(nodeApi, ENDPOINTS.GET_NOTIFICATIONS, { skip, limit });
      return { notifications: response.data.data || [], skip };
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to load notifications');
    }
  }
);

// ReadNotificationAttempt → post_services (BASE_URL, FormData + token)
export const markNotificationRead = createAsyncThunk(
  'notifications/markRead',
  async ({ notificationId }, { rejectWithValue }) => {
    try {
      await postFormData(nodeApi, ENDPOINTS.READ_NOTIFICATION, { notificationId });
      return notificationId;
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to mark as read');
    }
  }
);

// ViewAllNotificationAttempt → post_services (BASE_URL, FormData + token)
export const markAllRead = createAsyncThunk(
  'notifications/markAllRead',
  async (_, { rejectWithValue }) => {
    try {
      await postFormData(nodeApi, ENDPOINTS.VIEW_ALL_NOTIFICATIONS, {});
      return true;
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed');
    }
  }
);

// deleteNotificationAttempt → post_service5 (BASE_URL_3, JSON + token)
export const deleteNotification = createAsyncThunk(
  'notifications/delete',
  async ({ notificationId }, { rejectWithValue }) => {
    try {
      await dotnetApi.post(ENDPOINTS.DELETE_NOTIFICATION, { notificationId });
      return notificationId;
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to delete');
    }
  }
);
