/**
 * API helpers matching the mobile app's exact service patterns.
 *
 * Mobile app service files → web equivalents:
 *   post_services.js  → postFormData()      : BASE_URL (Node.js), POST, FormData, token in header
 *   post_services2.js → dotnetApi.post()    : BASE_URL_3 (.NET), POST, JSON, no auth header
 *   post_service5.js  → dotnetApi.post()    : BASE_URL_3 (.NET), POST, JSON, token in header
 *   get_service.js    → getNode()           : BASE_URL (Node.js), GET, token in header
 *   put_service.js    → putNoBody()         : BASE_URL (Node.js), PUT, no body, token in header
 *   put_services2.js  → putFormData()       : BASE_URL (Node.js), PUT, FormData, token in header
 */

/**
 * Convert plain object to FormData
 */
export const toFormData = (obj) => {
  const formData = new FormData();
  if (obj && typeof obj === 'object') {
    Object.keys(obj).forEach((key) => {
      if (obj[key] !== undefined && obj[key] !== null) {
        formData.append(key, obj[key]);
      }
    });
  }
  return formData;
};

/**
 * post_services.js pattern: POST with FormData to Node.js (BASE_URL)
 */
export const postFormData = (apiInstance, url, params) => {
  const formData = toFormData(params);
  return apiInstance.post(url, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  });
};

/**
 * get_service.js pattern: GET to Node.js (BASE_URL)
 * Token already injected by axios interceptor
 */
export const getNode = (apiInstance, url, queryParams = {}) => {
  const queryString = Object.entries(queryParams)
    .filter(([, v]) => v !== undefined && v !== null)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
    .join('&');
  const fullUrl = queryString ? `${url}?${queryString}` : url;
  return apiInstance.get(fullUrl);
};

/**
 * put_service.js pattern: PUT to Node.js (BASE_URL) with no body
 */
export const putNoBody = (apiInstance, url) => {
  return apiInstance.put(url);
};

/**
 * put_services2.js pattern: PUT with FormData to Node.js (BASE_URL)
 */
export const putFormData = (apiInstance, url, params) => {
  const formData = toFormData(params);
  return apiInstance.put(url, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  });
};
