import { nodeApi, dotnetApi } from '../axios';
import { ENDPOINTS } from '../config';
import { postFormData, putFormData } from '../helpers';

/**
 * Post service — matches mobile app's exact service patterns.
 * See actions/auth_actions.js and actions/friends_action.js
 */
const postService = {
  // CreateMyPostAttempt → post_services (BASE_URL, FormData multipart + token)
  createPost: (formData) => nodeApi.post(ENDPOINTS.CREATE_POST, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  // getMyPostAttempt → post_services (BASE_URL, FormData + token)
  getMyPosts: (params) => postFormData(nodeApi, ENDPOINTS.GET_MY_POSTS, params),
  // deleteMyPostAttempt → post_services (BASE_URL, FormData + token)
  deletePost: (params) => postFormData(nodeApi, ENDPOINTS.DELETE_POST, params),
  // EditMyPostAttempt → put_services2 (BASE_URL, PUT, FormData + token)
  editPost: (params) => putFormData(nodeApi, ENDPOINTS.EDIT_POST, params),
  // GetPostDataAttempt → post_services (BASE_URL, FormData + token)
  getPostDetail: (params) => postFormData(nodeApi, ENDPOINTS.POST_DETAIL, params),
  // getAnotherUserPostAttempt → post_services (BASE_URL, FormData + token)
  getOtherUserPosts: (params) => postFormData(nodeApi, ENDPOINTS.GET_OTHER_POSTS, params),
  // getAllUserPostAttempt → post_services (BASE_URL, FormData + token)
  getFriendsPosts: (params) => postFormData(nodeApi, ENDPOINTS.GET_FRIENDS_POSTS, params),
  // getPublicPostAttempt → post_services2 (BASE_URL_3, JSON)
  getPublicPosts: (params) => dotnetApi.post(ENDPOINTS.PUBLIC_POSTS, params),
  // sharePostOnTimelineAttempt → post_services2 (BASE_URL_3, JSON)
  sharePost: (data) => dotnetApi.post(ENDPOINTS.SHARE_POST, data),
  // myPostsLikeAttempt → post_services (BASE_URL, FormData + token)
  likeUnlike: (params) => postFormData(nodeApi, ENDPOINTS.LIKE_UNLIKE, params),
  // myPostsDislikeAttempt → post_services (BASE_URL, FormData + token)
  dislike: (params) => postFormData(nodeApi, ENDPOINTS.DISLIKE, params),
  // reportPostAttempt → post_services2 (BASE_URL_3, JSON)
  updateSensitivity: (data) => dotnetApi.post(ENDPOINTS.UPDATE_SENSITIVITY, data),
  // commentOnOff → post_services (BASE_URL, FormData)
  commentOnOff: (params) => postFormData(nodeApi, ENDPOINTS.COMMENT_ON_OFF, params),

  // Comments
  // myCommentsOnMyPostsAttempt → post_services (BASE_URL, FormData + token)
  postComment: (params) => postFormData(nodeApi, ENDPOINTS.POST_COMMENT, params),
  // getMyCommentsOnMyPostsAttempt → post_services (BASE_URL, FormData + token)
  getComments: (params) => postFormData(nodeApi, ENDPOINTS.GET_COMMENTS, params),
  // deleteCommentsAttempt → post_services (BASE_URL, FormData + token)
  deleteComment: (params) => postFormData(nodeApi, ENDPOINTS.DELETE_COMMENT, params),
  // updateMyCommentsOnMyPostsAttempt → put_services2 (BASE_URL, PUT, FormData + token)
  editComment: (params) => putFormData(nodeApi, ENDPOINTS.EDIT_COMMENT, params),
};

export default postService;
