import { useEffect, useCallback } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { getSocket } from '../api/socket';
import { addIncomingMessage, incrementUnread } from '../redux/slices/chatSlice';

const useSocket = () => {
  const { isAuthenticated, user } = useSelector((state) => state.auth);
  const { currentRecipientId } = useSelector((state) => state.chat);
  const dispatch = useDispatch();

  const handleNewMessage = useCallback((data) => {
    if (!data) return;
    const senderId = data.senderId?._id || data.senderId;

    // If we're in a chat with this sender, add the message
    if (currentRecipientId && senderId === currentRecipientId) {
      dispatch(addIncomingMessage(data));
    } else {
      // Otherwise increment unread count
      dispatch(incrementUnread());
    }
  }, [currentRecipientId, dispatch]);

  useEffect(() => {
    if (!isAuthenticated || !user?._id) return;

    const socket = getSocket();
    if (!socket) return;

    socket.on('newMessage', handleNewMessage);
    socket.on('chatMessage', handleNewMessage);

    return () => {
      socket.off('newMessage', handleNewMessage);
      socket.off('chatMessage', handleNewMessage);
    };
  }, [isAuthenticated, user?._id, handleNewMessage]);
};

export default useSocket;
