import React from 'react';
import './IncomingCallOverlay.css';

const IncomingCallOverlay = ({ callerName, callType, onAccept, onDecline }) => {
  return (
    <div className="incoming-call-overlay">
      <div className="incoming-call-card">
        <div className="incoming-call-avatar-placeholder">
          {(callerName[0] || 'U').toUpperCase()}
        </div>
        <p className="incoming-call-text">
          {callType === 'audio'
            ? `${callerName} is Calling You...`
            : `Video Call From ${callerName}`}
        </p>
        <div className="incoming-call-buttons">
          <button className="incoming-call-accept" onClick={onAccept}>
            📞 Accept
          </button>
          <button className="incoming-call-decline" onClick={onDecline}>
            ✕ Decline
          </button>
        </div>
      </div>
    </div>
  );
};

export default IncomingCallOverlay;
